383	      const count = stats.get(`fact:${s.topic}`) ?? 0;
384	      if (count >= 3) active.push(`fact:${s.topic} (${count})`);
385	      else if (count === 0) silentFacts.push(s.topic);
386	    }
387	    for (const [k, v] of stats) {
388	      if (k.startsWith("wiki:") && v >= 3) active.push(`${k} (${v})`);
389	      if (k.startsWith("skill:") && v >= 3) active.push(`${k} (${v})`);
390	    }
