392	      const indexRaw = readFileSync(path.join(config.memoryDir, "wiki", "index.md"), "utf8");
393	      const slugs = [...indexRaw.matchAll(/\[\[([^\]]+)\]\]/g)].map(m => m[1]);
394	      for (const slug of slugs) {
395	        if (!stats.has(`wiki:${slug}`)) silentWiki.push(slug);
396	      }
397	    } catch { /* no wiki index */ }
398	
399	    let report = "📊 **效用報告（過去 7 天）**\n\n";
400	    if (active.length > 0) {
401	      report += `✅ 活躍（≥3 次命中）：\n${active.slice(0, 15).map(a => `  ${a}`).join("\n")}\n\n`;
402	    }
403	    const silentTotal = silentFacts.length + silentWiki.length;
404	    if (silentTotal > 0) {
405	      report += `💤 沉默（0 次命中）：\n`;
406	      if (silentFacts.length) report += `  Facts: ${silentFacts.slice(0, 10).join(", ")}${silentFacts.length > 10 ? ` (+${silentFacts.length - 10})` : ""}\n`;
407	      if (silentWiki.length) report += `  Wiki: ${silentWiki.slice(0, 10).join(", ")}${silentWiki.length > 10 ? ` (+${silentWiki.length - 10})` : ""}\n`;
408	    }
