422	            `Format: name: reason`,
423	            { maxTokens: 150, timeout: 15000 },
424	          );
425	          if (raw) report += `\n🔍 沉默原因（LLM 判斷）：\n${raw}\n`;
426	        }
427	      } catch { /* Ollama unavailable — skip annotation */ }
428	    }
